import { UserService } from '../userService';
import { UserRepository, User, CreateUserDTO } from '../../types';

function createMockRepository(): jest.Mocked<UserRepository> {
  return {
    findById: jest.fn(),
    findByEmail: jest.fn(),
    create: jest.fn(),
    update: jest.fn(),
    delete: jest.fn(),
    listAll: jest.fn(),
  };
}

describe('UserService', () => {
  let mockRepo: jest.Mocked<UserRepository>;
  let service: UserService;

  beforeEach(() => {
    mockRepo = createMockRepository();
    service = new UserService(mockRepo);
  });

  it('should find user by id', async () => {
    const mockUser = { id: '1', name: 'Test', email: 'test@test.com' } as User;
    mockRepo.findById.mockResolvedValue(mockUser);
    const user = await service.findById('1');
    expect(user).toEqual(mockUser);
    expect(mockRepo.findById).toHaveBeenCalledWith('1');
  });

  it('should prevent duplicate email on create', async () => {
    const existingUser = { id: '1', name: 'Existing', email: 'dup@test.com' } as User;
    mockRepo.findByEmail.mockResolvedValue(existingUser);
    const dto: CreateUserDTO = { name: 'New', email: 'dup@test.com', passwordHash: 'hash' };
    await expect(service.create(dto)).rejects.toThrow('User with this email already exists');
  });
});

